{"action":"create","path":"game/scripts/Enemy.gd","content":"extends Area2D

@export var speed: float = 120.0
@export var health: int = 2
@export var score_value: int = 100
@export var enemy_bullet_scene: PackedScene
@export var shoot_interval: float = 2.5

var screen_size: Vector2
var move_direction: Vector2 = Vector2(1, 0)
var vertical_speed: float = 30.0
var shoot_timer: float = 0.0
var player_ref: Node = null
var is_dead: bool = false
var move_time: float = 0.0

@onready var sprite = $Sprite2D
@onready var collision = $CollisionShape2D

signal enemy_killed(score)

func _ready():
	screen_size = get_viewport_rect().size
	shoot_timer = randf_range(0.5, shoot_interval)
	move_time = randf_range(0, 10)

func _process(delta: float):
	if is_dead:
		return
	_handle_movement(delta)
	_handle_shooting(delta)
	_check_bounds()

func _handle_movement(delta: float):
	move_time += delta
	# Sine wave movement
	var sine_offset = sin(move_time * 2.0) * 80.0
	position.x += move_direction.x * speed * delta
	position.y += vertical_speed * delta
	# Bounce off walls
	if position.x >= screen_size.x - 30:
		move_direction.x = -1
	elif position.x <= 30:
		move_direction.x = 1

func _handle_shooting(delta: float):
	shoot_timer -= delta
	if shoot_timer <= 0:
		shoot_timer = shoot_interval
		_shoot()

func _shoot():
	if enemy_bullet_scene == null:
		return
	var bullet = enemy_bullet_scene.instantiate()
	bullet.position = position + Vector2(0, 30)
	# Aim at player if available
	if player_ref and is_instance_valid(player_ref):
		var dir = (player_ref.position - position).normalized()
		bullet.set_direction(dir)
	else:
		bullet.set_direction(Vector2(0, 1))
	get_parent().add_child(bullet)

func _check_bounds():
	# Remove if goes too far down
	if position.y > screen_size.y + 50:
		queue_free()

func take_hit():
	if is_dead:
		return
	health -= 1
	# Flash red when hit
	sprite.modulate = Color(1, 0.2, 0.2)
	var tween = create_tween()
	tween.tween_property(sprite, "modulate", Color(1, 1, 1), 0.15)
	if health <= 0:
		die()

func die():
	is_dead = true
	emit_signal("enemy_killed", score_value)
	collision.set_deferred("disabled", true)
	# Death animation
	var tween = create_tween()
	tween.tween_property(sprite, "scale", Vector2(2.0, 2.0), 0.2)
	tween.parallel().tween_property(sprite, "modulate", Color(1, 0.5, 0, 0), 0.2)
	tween.tween_callback(queue_free)

func set_player(player: Node):
	player_ref = player
"}

{"action":"create","path":"game/scripts/Main.gd","content":"extends Node2D

@export var player_scene: PackedScene
@export var enemy_scene: PackedScene
@export var bullet_scene: PackedScene
@export var enemy_bullet_scene: PackedScene

@onready var score_label = $UI/ScoreLabel
@onready var lives_label = $UI/LivesLabel
@onready var level_label = $UI/LevelLabel
@onready var high_score_label = $UI/HighScoreLabel
@onready var main_menu = $UI/MainMenu
@onready var game_over_screen = $UI/GameOverScreen
@onready var game_over_score = $UI/GameOverScreen/FinalScore
@onready var game_over_high = $UI/GameOverScreen/HighScore
@onready var hud = $UI/HUD
@onready var enemy_spawn_timer = $EnemySpawnTimer
@onready var background = $Background

var player: Node = null
var bg_scroll: float = 0.0
const BG_SCROLL_SPEED: float = 60.0

func _ready():
	GameManager.score_changed.connect(_on_score_changed)
	GameManager.lives_changed.connect(_on_lives_changed)
	GameManager.game_over.connect(_on_game_over)
	GameManager.level_up.connect(_on_level_up)
	_show_main_menu()

func _process(delta: float):
	# Scroll background
	bg_scroll += BG_SCROLL_SPEED * delta
	if bg_scroll >= 720:
		bg_scroll = 0
	if background:
		background.material.set_shader_parameter("scroll", bg_scroll)

func _show_main_menu():
	main_menu.visible = true
	game_over_screen.visible = false
	hud.visible = false
	if player:
		player.queue_free()
		player = null
	enemy_spawn_timer.stop()
	# Clear enemies and bullets
	_clear_entities()

func start_game():
	GameManager.start_game()
	main_menu.visible = false
	game_over_screen.visible = false
	hud.visible = true
	_clear_entities()
	# Spawn player
	player = player_scene.instantiate()
	player.bullet_scene = bullet_scene
	player.player_hit.connect(_on_player_hit)
	add_child(player)
	# Start spawning enemies
	enemy_spawn_timer.wait_time = 2.0
	enemy_spawn_timer.start()
	# Update UI
	_on_score_changed(0)
	_on_lives_changed(3)

func _clear_entities():
	for enemy in get_tree().get_nodes_in_group("enemies"):
		enemy.queue_free()
	for bullet in get_tree().get_nodes_in_group("bullets"):
		bullet.queue_free()
	for eb in get_tree().get_nodes_in_group("enemy_bullets"):
		eb.queue_free()

func _spawn_enemy():
	if not GameManager.game_active:
		return
	var enemy = enemy_scene.instantiate()
	enemy.enemy_bullet_scene = enemy_bullet_scene
	enemy.score_value = 100 * GameManager.get_level()
	enemy.speed = 80.0 + (GameManager.get_level() * 20.0)
	enemy.shoot_interval = max(1.0, 2.5 - (GameManager.get_level() * 0.2))
	var spawn_x = randf_range(40, 440)
	enemy.position = Vector2(spawn_x, -30)
	if player and is_instance_valid(player):
		enemy.set_player(player)
	enemy.enemy_killed.connect(_on_enemy_killed)
	add_child(enemy)
	# Adjust spawn rate based on level
	enemy_spawn_timer.wait_time = max(0.5, 2.0 - (GameManager.get_level() * 0.2))

func _on_enemy_killed(score: int):
	GameManager.add_score(score)

func _on_player_hit():
	GameManager.lose_life()
	if GameManager.get_lives() <= 0:
		if player:
			player.die()

func _on_score_changed(new_score: int):
	score_label.text = "Score: " + str(new_score)
	high_score_label.text = "Best: " + str(GameManager.get_high_score())

func _on_lives_changed(new_lives: int):
	var hearts = ""
	for i in range(new_lives):
		hearts += "❤ "
	lives_label.text = hearts

func _on_level_up(new_level: int):
	level_label.text = "Level: " + str(new_level)
	# Show level up message
	var label = Label.new()
	label.text = "LEVEL UP!"
	label.add_theme_font_size_override("font_size", 40)
	label.add_theme_color_override("font_color", Color(1, 1, 0))
	label.position = Vector2(140, 300)
	add_child(label)
	var tween = create_tween()
	tween.tween_property(label, "position", Vector2(140, 200), 1.0)
	tween.parallel().tween_property(label, "modulate", Color(1, 1, 0, 0), 1.0)
	tween.tween_callback(label.queue_free)

func _on_game_over():
	await get_tree().create_timer(1.5).timeout
	game_over_screen.visible = true
	hud.visible = false
	enemy_spawn_timer.stop()
	game_over_score.text = "Score: " + str(GameManager.get_score())
	game_over_high.text = "Best: " + str(GameManager.get_high_score())

func _on_enemy_spawn_timer_timeout():
	_spawn_enemy()
	# Spawn extra enemies at higher levels
	if GameManager.get_level() >= 3:
		await get_tree().create_timer(0.5).timeout
		_spawn_enemy()

func _on_start_button_pressed():
	start_game()

func _on_restart_button_pressed():
	start_game()

func _on_menu_button_pressed():
	_show_main_menu()
"}
